// SketchCanvas — HTML5 canvas mount for the Family Creator sketcher (S52 D1).
//
// Orchestrates: store ↔ tool ↔ pointer events ↔ paint cycle.
// Pure rendering helpers live in `sketchRender.ts`; this file owns
// the DOM scaffold + event wiring so the §13 300-LoC cap holds.
//
// Rules enforced here:
//  - No `(window as any)` (rule P6).
//  - No `requestAnimationFrame` — paints are flushed via `queueMicrotask`
//    until the global frame-scheduler lands in S53 (rule P3).
//  - No THREE import (rule P2).

import {
  createSketchDocStore,
  type SketchDocStore,
} from '../stores/sketchDocStore.js';
import { snapCursor, type SnapHit } from './snap.js';
import { canvasToWorld, defaultView, type ViewState } from './transform.js';
import {
  drawBackground,
  drawEntities,
  drawGrid,
  drawPreview,
  drawSnapIndicator,
} from './sketchRender.js';
import { createLineTool } from './tools/LineTool.js';
import { createRectangleTool } from './tools/RectangleTool.js';
import {
  EMPTY_PREVIEW,
  type SketchTool,
  type ToolName,
  type ToolPreview,
} from './tools/types.js';

const GRID_SIZE_MM = 100;
const SNAP_RADIUS_PX = 12;

export interface SketchCanvasMount {
  readonly element: HTMLElement;
  unmount(): void;
  readonly store: SketchDocStore;
  setActiveTool(name: ToolName): void;
  getActiveToolName(): ToolName;
}

export function mountSketchCanvas(host: HTMLElement, store?: SketchDocStore): SketchCanvasMount {
  const docStore = store ?? createSketchDocStore();

  const root = document.createElement('div');
  root.dataset.role = 'sketch-canvas-root';
  root.style.cssText = 'display:flex;flex-direction:column;height:100%;background:#0a0a18';

  const toolbar = renderToolbar((name) => switchTool(name));
  const canvasWrap = document.createElement('div');
  canvasWrap.style.cssText = 'flex:1;position:relative;overflow:hidden';
  const canvas = document.createElement('canvas');
  canvas.dataset.role = 'sketch-canvas';
  canvas.tabIndex = 0;
  canvas.style.cssText = 'width:100%;height:100%;display:block;cursor:crosshair;outline:none';
  canvasWrap.appendChild(canvas);

  const hud = document.createElement('div');
  hud.dataset.role = 'sketch-hud';
  hud.style.cssText =
    'position:absolute;left:8px;bottom:8px;color:#a8a8c0;font:12px/1.4 monospace;pointer-events:none;text-shadow:0 0 4px #000;white-space:pre';
  canvasWrap.appendChild(hud);

  root.append(toolbar, canvasWrap);
  host.appendChild(root);

  let view: ViewState = defaultView(800, 600);
  let cursorWorld: { x: number; z: number } | null = null;
  let lastSnap: SnapHit | null = null;
  let preview: ToolPreview = EMPTY_PREVIEW;
  let activeTool: SketchTool = createLineTool({
    commitLine: (l) => docStore.addLineByCoords(l.x1, l.z1, l.x2, l.z2),
  });

  function switchTool(name: ToolName): void {
    activeTool.reset();
    activeTool = (name === 'rectangle' ? createRectangleTool : createLineTool)({
      commitLine: (l) => docStore.addLineByCoords(l.x1, l.z1, l.x2, l.z2),
    });
    preview = EMPTY_PREVIEW;
    paintToolbarSelection(toolbar, name);
    schedulePaint();
  }

  function paint(): void {
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const snap = docStore.get();
    drawBackground(ctx, view);
    drawGrid(ctx, view, GRID_SIZE_MM);
    drawEntities(ctx, snap, view);
    drawPreview(ctx, preview, view);
    if (lastSnap) drawSnapIndicator(ctx, lastSnap, view);
    paintHud(hud, cursorWorld, lastSnap, preview, activeTool.name);
  }

  let painting = false;
  function schedulePaint(): void {
    if (painting) return;
    painting = true;
    queueMicrotask(() => {
      painting = false;
      paint();
    });
  }

  function resize(): void {
    const rect = canvas.getBoundingClientRect();
    const w = Math.max(1, Math.floor(rect.width || 800));
    const h = Math.max(1, Math.floor(rect.height || 600));
    canvas.width = w;
    canvas.height = h;
    view = { ...view, canvasW: w, canvasH: h };
    schedulePaint();
  }

  function dispatch(kind: 'pointer-move' | 'pointer-down', e: PointerEvent): void {
    const rect = canvas.getBoundingClientRect();
    const world = canvasToWorld({ px: e.clientX - rect.left, py: e.clientY - rect.top }, view);
    const snap = snapCursor({
      cursorX: world.x,
      cursorZ: world.z,
      entities: docStore.get().entities,
      snapRadiusMm: SNAP_RADIUS_PX / view.zoom,
      gridSizeMm: GRID_SIZE_MM,
    });
    cursorWorld = { x: snap.x, z: snap.z };
    lastSnap = snap;
    preview = activeTool.handle({ kind, worldX: snap.x, worldZ: snap.z, snap });
    schedulePaint();
  }

  const onMove = (e: PointerEvent): void => dispatch('pointer-move', e);
  const onDown = (e: PointerEvent): void => {
    canvas.focus();
    dispatch('pointer-down', e);
  };
  const onKey = (e: KeyboardEvent): void => {
    if (e.key === 'Escape') {
      preview = activeTool.reset();
      schedulePaint();
    }
  };
  canvas.addEventListener('pointermove', onMove);
  canvas.addEventListener('pointerdown', onDown);
  canvas.addEventListener('keydown', onKey);

  const unsubscribeStore = docStore.subscribe(() => schedulePaint());
  resize();

  return {
    element: root,
    store: docStore,
    setActiveTool: switchTool,
    getActiveToolName: () => activeTool.name,
    unmount() {
      canvas.removeEventListener('pointermove', onMove);
      canvas.removeEventListener('pointerdown', onDown);
      canvas.removeEventListener('keydown', onKey);
      unsubscribeStore();
      host.removeChild(root);
    },
  };
}

function renderToolbar(onSelect: (name: ToolName) => void): HTMLElement {
  const bar = document.createElement('div');
  bar.dataset.role = 'sketch-toolbar';
  bar.style.cssText =
    'display:flex;gap:4px;padding:6px 12px;background:rgba(0,0,0,0.3);border-bottom:1px solid rgba(255,255,255,0.08)';
  for (const tool of [
    { id: 'line' as ToolName, label: 'Line' },
    { id: 'rectangle' as ToolName, label: 'Rectangle' },
  ]) {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.dataset.tool = tool.id;
    btn.textContent = tool.label;
    btn.style.cssText = toolButtonStyle(tool.id === 'line');
    btn.addEventListener('click', () => onSelect(tool.id));
    bar.appendChild(btn);
  }
  return bar;
}

function paintToolbarSelection(toolbar: HTMLElement, active: ToolName): void {
  for (const btn of Array.from(toolbar.querySelectorAll<HTMLButtonElement>('button[data-tool]'))) {
    btn.style.cssText = toolButtonStyle(btn.dataset.tool === active);
  }
}

function toolButtonStyle(active: boolean): string {
  return [
    `background:${active ? '#6600FF' : 'transparent'}`,
    `color:${active ? '#fff' : '#a8a8c0'}`,
    'border:1px solid rgba(255,255,255,0.15)',
    'padding:4px 12px',
    'border-radius:4px',
    'font:12px/1.4 system-ui',
    'cursor:pointer',
  ].join(';');
}

function paintHud(
  hud: HTMLElement,
  cursor: { x: number; z: number } | null,
  snap: SnapHit | null,
  preview: ToolPreview,
  tool: ToolName,
): void {
  const lines: string[] = [`Tool: ${tool}`];
  if (cursor) lines.push(`X: ${cursor.x.toFixed(1)}   Z: ${cursor.z.toFixed(1)} mm`);
  if (snap && snap.kind !== 'none') lines.push(`Snap: ${snap.kind}`);
  if (preview.hint) lines.push(preview.hint);
  hud.textContent = lines.join('\n');
}
