/**
 * AppShell — the layout host for the PRYZM Family Creator.
 *
 * S52 D1 ships this with a real view-tab bar consuming the
 * `viewTabStore`. The three view panels (sketch / 3D / parameters)
 * land incrementally across S52–S55 per the rewrite plan §19; today
 * they render a labelled placeholder so the tab transitions are
 * end-to-end exercisable.
 *
 * Constraints already enforced by this file:
 *  - No `(window as any)` — rule P6.
 *  - No `requestAnimationFrame` here — that's owned by the global
 *    `@pryzm/frame-scheduler` (rule P3).
 *  - No THREE import — that lives only in committers (rule P2).
 *  - ≤ 300 LoC per file (the §13 `family-editor-300-loc-cap` gate).
 */

import { createViewTabStore, type ViewTab, type ViewTabStore } from '../stores/viewTabStore.js';
import { mountSketchCanvas } from '../sketch/SketchCanvas.js';

const PLAN_PATH =
  'docs/00_NEW_ARCHITECTURE/phases/PHASE-3B-FAMILY-CREATOR-REWRITE-PLAN.md';

const TAB_LABELS: ReadonlyArray<{ readonly id: ViewTab; readonly label: string }> = [
  { id: 'sketch', label: 'Sketch' },
  { id: '3d', label: '3D' },
  { id: 'parameters', label: 'Parameters' },
];

export interface MountResult {
  unmount(): void;
  /** Test seam — exposes the live store so tests can drive transitions. */
  readonly viewTabStore: ViewTabStore;
}

export function mountAppShell(root: HTMLElement): MountResult {
  root.innerHTML = '';
  root.style.cssText = [
    'display:flex',
    'flex-direction:column',
    'height:100vh',
    'margin:0',
    'background:linear-gradient(135deg,#1a1a2e 0%,#0f0f1f 100%)',
    'color:#e8e8f0',
    'font-family:system-ui,sans-serif',
  ].join(';');

  const viewTabStore = createViewTabStore('sketch');
  const tabBar = renderTabBar(viewTabStore);
  let activeMount = renderActivePanel(viewTabStore.get().active);
  const unsubscribe = viewTabStore.subscribe((snap) => {
    repaintTabBar(tabBar, snap.active);
    activeMount.cleanup();
    const next = renderActivePanel(snap.active);
    activeMount.element.replaceWith(next.element);
    activeMount = next;
  });

  root.append(renderHeader(), tabBar, activeMount.element, renderFooter());

  return {
    unmount() {
      unsubscribe();
      activeMount.cleanup();
      root.innerHTML = '';
    },
    viewTabStore,
  };
}

function renderTabBar(store: ViewTabStore): HTMLElement {
  const bar = document.createElement('nav');
  bar.dataset.role = 'view-tab-bar';
  bar.setAttribute('aria-label', 'View tabs');
  bar.style.cssText = [
    'display:flex',
    'gap:4px',
    'padding:8px 24px',
    'border-bottom:1px solid rgba(255,255,255,0.1)',
    'background:rgba(0,0,0,0.2)',
  ].join(';');

  for (const { id, label } of TAB_LABELS) {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.dataset.tab = id;
    btn.textContent = label;
    btn.setAttribute('role', 'tab');
    btn.setAttribute('aria-selected', String(id === store.get().active));
    btn.style.cssText = tabButtonStyle(id === store.get().active);
    btn.addEventListener('click', () => store.setActive(id));
    bar.appendChild(btn);
  }
  return bar;
}

function repaintTabBar(bar: HTMLElement, active: ViewTab): void {
  for (const btn of Array.from(bar.querySelectorAll<HTMLButtonElement>('button[data-tab]'))) {
    const isActive = btn.dataset.tab === active;
    btn.setAttribute('aria-selected', String(isActive));
    btn.style.cssText = tabButtonStyle(isActive);
  }
}

function tabButtonStyle(active: boolean): string {
  return [
    `background:${active ? '#6600FF' : 'transparent'}`,
    `color:${active ? '#ffffff' : '#a8a8c0'}`,
    'border:none',
    'padding:8px 16px',
    'border-radius:6px',
    'font-weight:600',
    'cursor:pointer',
    'font-size:13px',
    'font-family:inherit',
  ].join(';');
}

interface PanelMount {
  readonly element: HTMLElement;
  cleanup(): void;
}

function renderActivePanel(active: ViewTab): PanelMount {
  const panel = document.createElement('section');
  panel.dataset.role = 'view-panel';
  panel.dataset.activeTab = active;
  panel.setAttribute('aria-label', `${active} view`);
  panel.style.cssText = 'flex:1;overflow:hidden;display:flex;flex-direction:column';

  if (active === 'sketch') {
    const sketch = mountSketchCanvas(panel);
    return { element: panel, cleanup: () => sketch.unmount() };
  }
  panel.style.cssText = 'flex:1;overflow:auto';
  panel.appendChild(renderSplash(active));
  return { element: panel, cleanup: () => undefined };
}

function renderHeader(): HTMLElement {
  const header = document.createElement('header');
  header.style.cssText = [
    'padding:16px 24px',
    'border-bottom:1px solid rgba(255,255,255,0.1)',
    'display:flex',
    'align-items:center',
    'gap:12px',
  ].join(';');

  const logo = document.createElement('div');
  logo.textContent = 'PRYZM';
  logo.style.cssText = 'font-weight:700;color:#6600FF;font-size:18px;letter-spacing:1px';

  const subtitle = document.createElement('div');
  subtitle.textContent = 'Family Creator';
  subtitle.style.cssText = 'font-size:14px;color:#a8a8c0';

  header.append(logo, subtitle);
  return header;
}

const PANEL_TITLES: Readonly<Record<ViewTab, string>> = {
  sketch: 'Sketch — under construction',
  '3d': '3D preview — under construction',
  parameters: 'Parameter table — under construction',
};

function renderSplash(active: ViewTab): HTMLElement {
  const splash = document.createElement('section');
  splash.setAttribute('aria-labelledby', 'fce-splash-title');
  splash.style.cssText = [
    'flex:1',
    'display:flex',
    'flex-direction:column',
    'align-items:center',
    'justify-content:center',
    'padding:48px 24px',
    'text-align:center',
    'gap:24px',
  ].join(';');

  const title = document.createElement('h1');
  title.id = 'fce-splash-title';
  title.textContent = PANEL_TITLES[active];
  title.style.cssText = 'margin:0;font-size:32px;font-weight:700';

  const lede = document.createElement('p');
  lede.textContent =
    'A standalone, parametric Family Creator is being rebuilt from the ground up.';
  lede.style.cssText = 'margin:0;max-width:560px;line-height:1.6;color:#b8b8d0;font-size:16px';

  const sub = document.createElement('p');
  sub.textContent =
    'The previous prototype has been removed; the new editor will land progressively over sprints S52–S59.';
  sub.style.cssText = 'margin:0;max-width:560px;line-height:1.6;color:#9090a8;font-size:14px';

  const planLine = document.createElement('p');
  planLine.style.cssText = 'margin:0;font-size:13px;color:#7878a0';
  planLine.textContent = 'Implementation plan: ';
  const code = document.createElement('code');
  code.textContent = PLAN_PATH;
  code.style.cssText =
    'background:rgba(102,0,255,0.15);padding:4px 8px;border-radius:4px;color:#c8b8ff;font-size:12px';
  planLine.appendChild(code);

  splash.append(title, lede, sub, planLine, renderRoadmap());
  return splash;
}

function renderRoadmap(): HTMLElement {
  const wrapper = document.createElement('section');
  wrapper.setAttribute('aria-label', 'Sprint roadmap');
  wrapper.style.cssText = [
    'margin-top:24px',
    'padding:24px',
    'background:rgba(255,255,255,0.04)',
    'border:1px solid rgba(255,255,255,0.08)',
    'border-radius:12px',
    'max-width:720px',
    'width:calc(100% - 48px)',
    'text-align:left',
  ].join(';');

  const heading = document.createElement('h2');
  heading.textContent = 'Sprint roadmap (S52 → S59)';
  heading.style.cssText = 'margin:0 0 16px;font-size:14px;font-weight:600;color:#a8a8c0;text-transform:uppercase;letter-spacing:1px';
  wrapper.appendChild(heading);

  const sprints: Array<[string, string]> = [
    ['S52', 'Removal + scaffolding + real planegcs constraint solver + first 5 constraints + extrude'],
    ['S53', 'Sketch tools (line, arc, circle, fillet, trim) + sweep / loft / revolve + booleans'],
    ['S54', 'AI host bridge + tool registry + batch undo'],
    ['S55', 'Parameter table + expression DSL + IFC Pset binding + .pryzm-family v1'],
    ['S56', 'Main-editor integration (load family, place 200 instances, swap types)'],
    ['S57', 'Versioning + migration framework + performance hardening'],
    ['S58', 'Standalone SPA deploy + accessibility + end-to-end tests'],
    ['S59', 'Marketplace publish + Phase 3B exit'],
  ];

  const list = document.createElement('ul');
  list.style.cssText = 'margin:0;padding:0;list-style:none;display:flex;flex-direction:column;gap:8px';
  for (const [sprint, desc] of sprints) {
    const item = document.createElement('li');
    item.style.cssText = 'display:flex;gap:12px;font-size:13px;line-height:1.5';

    const tag = document.createElement('span');
    tag.textContent = sprint;
    tag.style.cssText =
      'flex:0 0 48px;font-weight:700;color:#6600FF;font-family:ui-monospace,monospace';

    const text = document.createElement('span');
    text.textContent = desc;
    text.style.cssText = 'color:#c8c8e0';

    item.append(tag, text);
    list.appendChild(item);
  }
  wrapper.appendChild(list);
  return wrapper;
}

function renderFooter(): HTMLElement {
  const footer = document.createElement('footer');
  footer.style.cssText = [
    'padding:16px 24px',
    'border-top:1px solid rgba(255,255,255,0.1)',
    'font-size:12px',
    'color:#7878a0',
    'text-align:center',
  ].join(';');
  footer.textContent = '© PRYZM — vanilla TypeScript, no React. Layer L7 chrome.';
  return footer;
}
